import{_ as a,c as t,o,aj as r}from"./chunks/framework.BlveriQe.js";const p=JSON.parse('{"title":"Interface: DatabaseInfo","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/DatabaseInfo.md","filePath":"reference/js-bao-wss-client/api/interfaces/DatabaseInfo.md"}'),d={name:"reference/js-bao-wss-client/api/interfaces/DatabaseInfo.md"};function c(s,e,i,n,l,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / DatabaseInfo</p><h1 id="interface-databaseinfo" tabindex="-1">Interface: DatabaseInfo <a class="header-anchor" href="#interface-databaseinfo" aria-label="Permalink to “Interface: DatabaseInfo”">​</a></h1><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="celcontext" tabindex="-1"><s>celContext</s> <a class="header-anchor" href="#celcontext" aria-label="Permalink to “celContext”">​</a></h3><blockquote><p><strong>celContext</strong>: <code>Record</code>&lt;<code>string</code>, <code>any</code>&gt; | <code>null</code></p></blockquote><p>User-facing name for the CEL context dict attached to this database. Values here are referenced from CEL access rules as <code>database.celContext.&lt;key&gt;</code> (or the legacy <code>database.metadata.&lt;key&gt;</code>) and from filter JSON as <code>$database.celContext.&lt;key&gt;</code>.</p><h4 id="deprecated" tabindex="-1">Deprecated <a class="header-anchor" href="#deprecated" aria-label="Permalink to “Deprecated”">​</a></h4><p>Prefer resource metadata categories (issue #1420). A category carries separate <code>readRule</code>/<code>writeRule</code>, so granting read no longer implies granting update — the foot-gun of the CEL-context access gate (<code>metadataAccess</code>), which gates read AND update with a single expression. Declare a category in the database type config&#39;s <code>metadataManifest</code> and read it from CEL as <code>md.self.&lt;category&gt;.&lt;key&gt;</code>. See the migration recipe in <code>databases.md</code>. The field keeps working; nothing is removed here.</p><hr><h3 id="createdat" tabindex="-1">createdAt <a class="header-anchor" href="#createdat" aria-label="Permalink to “createdAt”">​</a></h3><blockquote><p><strong>createdAt</strong>: <code>string</code></p></blockquote><hr><h3 id="createdby" tabindex="-1">createdBy <a class="header-anchor" href="#createdby" aria-label="Permalink to “createdBy”">​</a></h3><blockquote><p><strong>createdBy</strong>: <code>string</code></p></blockquote><hr><h3 id="databaseid" tabindex="-1">databaseId <a class="header-anchor" href="#databaseid" aria-label="Permalink to “databaseId”">​</a></h3><blockquote><p><strong>databaseId</strong>: <code>string</code></p></blockquote><hr><h3 id="databasetype" tabindex="-1">databaseType <a class="header-anchor" href="#databasetype" aria-label="Permalink to “databaseType”">​</a></h3><blockquote><p><strong>databaseType</strong>: <code>string</code> | <code>null</code></p></blockquote><hr><h3 id="metadata" tabindex="-1"><s>metadata</s> <a class="header-anchor" href="#metadata" aria-label="Permalink to “metadata”">​</a></h3><blockquote><p><strong>metadata</strong>: <code>Record</code>&lt;<code>string</code>, <code>any</code>&gt; | <code>null</code></p></blockquote><h4 id="deprecated-1" tabindex="-1">Deprecated <a class="header-anchor" href="#deprecated-1" aria-label="Permalink to “Deprecated”">​</a></h4><p>Prefer resource metadata categories (issue #1420) — a category has separate <code>readRule</code>/<code>writeRule</code> (granting read no longer grants update) and is read from CEL as <code>md.self.&lt;category&gt;.&lt;key&gt;</code>. See the migration recipe in <code>databases.md</code>. This field is the legacy wire-level name for the same dict as the (also-deprecated) <a href="#celcontext">celContext</a>; it stays for backwards compatibility with stored CEL expressions that reference <code>database.metadata.&lt;key&gt;</code>.</p><hr><h3 id="modifiedat" tabindex="-1">modifiedAt <a class="header-anchor" href="#modifiedat" aria-label="Permalink to “modifiedAt”">​</a></h3><blockquote><p><strong>modifiedAt</strong>: <code>string</code></p></blockquote><hr><h3 id="permission" tabindex="-1">permission <a class="header-anchor" href="#permission" aria-label="Permalink to “permission”">​</a></h3><blockquote><p><strong>permission</strong>: <code>string</code> | <code>null</code></p></blockquote><hr><h3 id="title" tabindex="-1">title <a class="header-anchor" href="#title" aria-label="Permalink to “title”">​</a></h3><blockquote><p><strong>title</strong>: <code>string</code></p></blockquote>',36)])])}const f=a(d,[["render",c]]);export{p as __pageData,f as default};
